--
-- Table structure for table `task_warning`
--

DROP TABLE IF EXISTS `task_warning`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `task_warning` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'дё»й”®',
  `user_id` bigint NOT NULL COMMENT 'жҺҘж”¶дәәз”ЁжҲ·ID',
  `warn_type` varchar(20) NOT NULL COMMENT 'йў„иӯҰзұ»еһӢ: deadline_soon=еҚіе°Ҷи¶…ж—¶, overdue=е·Іи¶…ж—¶',
  `proc_inst_id` varchar(64) NOT NULL COMMENT 'жөҒзЁӢе®һдҫӢID',
  `proc_name` varchar(200) DEFAULT NULL COMMENT 'жөҒзЁӢеҗҚз§°',
  `task_name` varchar(200) DEFAULT NULL COMMENT 'д»»еҠЎеҗҚз§°пјҲз”ЁжҲ·еЎ«еҶҷзҡ„жөҒзЁӢеҗҚз§°пјү',
  `team_name` varchar(100) DEFAULT NULL COMMENT 'жү§иЎҢзҸӯз»„еҗҚз§°',
  `node_key` varchar(100) NOT NULL COMMENT 'иҠӮзӮ№key(BPMN ID)',
  `node_name` varchar(100) DEFAULT NULL COMMENT 'иҠӮзӮ№еҗҚз§°',
  `end_date` varchar(10) NOT NULL COMMENT 'иҠӮзӮ№и®ЎеҲ’з»“жқҹж—Ҙжңҹ yyyy-MM-dd',
  `is_read` tinyint NOT NULL DEFAULT '0' COMMENT 'жҳҜеҗҰе·ІиҜ»: 0=жңӘиҜ», 1=е·ІиҜ»',
  `resolved` tinyint NOT NULL DEFAULT '0' COMMENT 'жҳҜеҗҰе·ІеӨ„зҗҶ: 0=жңӘеӨ„зҗҶ, 1=е·ІеӨ„зҗҶ',
  `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ',
  `admin_read` tinyint(1) DEFAULT '0' COMMENT 'з®ЎзҗҶе‘ҳе·ІиҜ»: 0=жңӘиҜ», 1=е·ІиҜ»',
  PRIMARY KEY (`id`),
  KEY `idx_user_read` (`user_id`,`is_read`),
  KEY `idx_proc_node` (`proc_inst_id`,`node_key`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='д»»еҠЎиҠӮзӮ№и¶…ж—¶йў„иӯҰж¶ҲжҒҜ';
